var e=[{id:`L3_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`하아…… 하아……`,JPN:`はあ……はあ……`,ENG:`*Huff...* *Huff...*`,TWN:`呼呼……呼呼……`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`있을 수 없는 일이야. 내 미래가…… 어째서……`,JPN:`ありえない。私の未来が……どうして……`,ENG:`This can't be. My future... But why...?`,TWN:`這不可能，我的未來……為什麼……`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CHIFUYU_NANA_CA_NULL`,text:{KOREA:`지쳤나?`,JPN:`疲れたか？`,ENG:`Exhausted already?`,TWN:`累了嗎？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_CA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`크으읏……!`,JPN:`くうぅ……！`,ENG:`Krrgh...!`,TWN:`咳呃呃……！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`하등한 것 따위가!!!`,JPN:`下等の分際で！！！`,ENG:`You worthless little...!!!`,TWN:`你這個低等生物！！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`아아…… 으아아…… 아파.`,JPN:`ああ……うわあ……痛い。`,ENG:`Ahh... Aagh... It hurts.`,TWN:`啊啊……呃啊啊……好痛。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`싫어. 이런 건……`,JPN:`いや。こんなの……`,ENG:`No. I don't like this...`,TWN:`可惡，我……`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`인정 못해!`,JPN:`認められない！`,ENG:`I won't accept this!`,TWN:`我不承認！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`아아아아아악!!!!`,JPN:`ああああああっ！！！！`,ENG:`AAAGH!!`,TWN:`啊啊啊啊啊啊！！！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`뜨거워! 뜨겁다고!!!`,JPN:`熱い！　熱いよ！！！`,ENG:`It's hot! It's burning!!!`,TWN:`好燙！好燙！！！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:null,R:null}}},{id:`L28_1`,type:`dialog`,speaker:`GENERAL_NPC_NOA_NULL`,text:{KOREA:`예정보다 늦더니 고전하고 있구나, 레노어.`,JPN:`予定より遅れると思ったら苦戦しているな、レノア。`,ENG:`Lenore, I came to see what was taking so long. You are struggling.`,TWN:`我還在想怎麼比我預期的還慢，原來你陷入苦戰嗎，蕾諾雅？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`GENERAL_NPC_NOA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`아…… 아버지……?`,JPN:`お……お父様……？`,ENG:`F-father...?`,TWN:`父……父親……？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`아뇨, 할 수 있어요. 아직 이길 수 있어요!`,JPN:`いいえ、できます。まだ勝てます！`,ENG:`No, I can do this. I can still win!`,TWN:`不是的，我可以的，我會贏的！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`GENERAL_NPC_NOA_NULL`,text:{KOREA:`그 대답은 관측에 따른 것이냐, 아니면 단지 너의 만용이냐?`,JPN:`その答えは観測によるものか、それとも単なる貴様の驕りか？`,ENG:`Is that answer derived from observation, or is it merely your hopes?`,TWN:`這句話是你從觀測而得知的，還是單純是你的匹夫之勇呢？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`GENERAL_NPC_NOA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`아버지…… 저는……!`,JPN:`お父様……私は……！`,ENG:`But father...! I...!`,TWN:`父親……我……！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};